import{_ as s,c as a,a as i,o as n}from"./app-CEcM0piI.js";const t={};function l(r,e){return n(),a("div",null,e[0]||(e[0]=[i(`<p>react-router是react的路由库，其中包含默认，dom，native，any</p><ul><li>默认的react-router是服务端渲染使用的</li><li>dom：用于react的web应用</li><li>native：用于react native移动端应用</li><li>any：二者都能使用</li></ul><h2 id="web" tabindex="-1"><a class="header-anchor" href="#web"><span>web</span></a></h2><p>库名为：react-router-dom</p><p><strong>常用组件</strong></p><ul><li>BrowserRouter：history模式的路由器</li><li>HashRouter：hash模式的路由器</li><li>Link：用于路由跳转，但必须要被包裹在Router组件中，被点击后会将路由跳转的信息发送给包裹自己的router组件，由在同一个router组件中的route显示相应的内容</li><li>Route：用于路由组件展示，必须被包裹在Router组件中，需要在内部指定匹配的路径和要加载的组件</li><li>NavLink：被点击时会给自身默认添加一个active的类名，其他的和Link一样。也可以自己指定active的类名，使用activeClassName属性</li><li>Switch：用于包裹Route标签，如果没有使用switch组件包裹的route组件多个route组件匹配同一个路由时就会都显示出来，如果使用Swtich组件包裹的route组件之会找到第一个匹配的显示出来并返回</li><li>Redirect：重定向，通常写在Switch组件中，如果前面的路由都无法匹配那么就跳转Redirect指定的路由</li></ul><p>路由在跳转时会默认给对应的组件传props，即使组件没有定义props</p><ul><li>history：其中带有用于函数式编程导航的函数</li><li>location：</li><li>match：</li></ul><p><strong>两个link默认都是push模式，可以将replace属性指定为true改为replace模式</strong></p><blockquote><p>[!NOTE] Title 使用BrowserRouter跳转时有多个/分隔子路径如：/index/food可能会导致css样式丢失问题，路由可能会将子路径前的路径也添加到url当做资源路径中从服务器获取资源，这种情况需要将./css引入的样式改成/css，或者使用hash模式</p></blockquote><h3 id="模糊匹配" tabindex="-1"><a class="header-anchor" href="#模糊匹配"><span>模糊匹配</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;Router&gt;</span></span>
<span class="line"><span>	&lt;NavLink to=&#39;/home&#39;&gt;home&lt;/NavLink&gt;  //都可以匹配到</span></span>
<span class="line"><span>	&lt;NavLink to=&#39;/home/a/b&#39;&gt;home&lt;/NavLink&gt; //第一个route可以匹配到</span></span>
<span class="line"><span>	&lt;NavLink to=&#39;/a/home&#39;&gt;home&lt;/NavLink&gt; //都不能匹配到</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	&lt;Route path=&#39;/home&#39;&gt;&lt;/Route&gt;</span></span>
<span class="line"><span>	&lt;Route exact={true} path=&#39;/home&#39;&gt;&lt;/Route&gt;  //开启严格模式</span></span>
<span class="line"><span>&lt;/Router&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果匹配到的路径后续还有多余路径那么Route也会进行拆分并跳转到首个路径，开启严格模式后就只能匹配完全相同的路径</p><p><strong>开启严格模式后该路径下也无法匹配子路径了，请慎重开启</strong></p><h3 id="多级路由" tabindex="-1"><a class="header-anchor" href="#多级路由"><span>多级路由</span></a></h3><p>要实现多级路由只能从根路径开始指定</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;NavLink to=&#39;/home/a/b/c&#39;&gt;home&lt;/NavLink&gt;</span></span>
<span class="line"><span>&lt;Route path=&#39;/home/a/b/c&#39;&gt;&lt;/Route&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="路由传参" tabindex="-1"><a class="header-anchor" href="#路由传参"><span>路由传参</span></a></h3><h4 id="params" tabindex="-1"><a class="header-anchor" href="#params"><span>params</span></a></h4><p>路由传参的params在跳转时传参的match属性中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;NavLink to=\`/home/\${id}\`&gt;home&lt;/NavLink&gt;</span></span>
<span class="line"><span>&lt;Route path=&#39;/home/:id&#39;&gt;&lt;/Route&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>在对应要显示的组件中使用<code>this.props.match.params</code>就可以获取到路由传递的参数了</p><h4 id="search" tabindex="-1"><a class="header-anchor" href="#search"><span>search</span></a></h4><p>路由传参的params在跳转时传参的location属性中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;NavLink to=\`/home?id=\${id}&amp;name=\${name}\`&gt;home&lt;/NavLink&gt;</span></span>
<span class="line"><span>&lt;Route path=&#39;/home&#39;&gt;&lt;/Route&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>在对应要显示的组件中使用<code>this.props.location.query</code>就可以获取到路由传递的参数了 但是获取到的是一个字符串，还需要使用react自带的库解析出来</p><h4 id="state" tabindex="-1"><a class="header-anchor" href="#state"><span>state</span></a></h4><p>路由传参的state在跳转时传参的location属性中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;NavLink to={{pathname:&#39;/home&#39;,state:{id:this.id,name:this.name}}}&gt;home&lt;/NavLink&gt;</span></span>
<span class="line"><span>&lt;Route path=&#39;/home&#39;&gt;&lt;/Route&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>在对应要显示的组件中使用<code>this.props.location.state</code>就可以获取到路由传递的参数了</p><p>使用state传值虽然不会在地址栏中显示出来，但是刷新页面后依旧不会丢失state的值，因为路由跳转是由Router组件维护的，它维护了bom的history，在跳转前Router组件就将state维护到bom带history中</p><h3 id="编程式路由导航" tabindex="-1"><a class="header-anchor" href="#编程式路由导航"><span>编程式路由导航</span></a></h3><p>在路由跳转时会传递三个props：history、location、match 在history中带有push、replace、back、forward等函数可以用于编程式路由导航</p><h4 id="withrouter" tabindex="-1"><a class="header-anchor" href="#withrouter"><span>withRouter</span></a></h4><p><strong>但如果没有其他路由跳转到该组件时就无法使用history、location、match等api</strong></p><p>使用withRouter函数包装组件和，返回的组件就具有这三个api了可以使用编程式路由导航了</p><h3 id="配置路由" tabindex="-1"><a class="header-anchor" href="#配置路由"><span>配置路由</span></a></h3><p>使用createBrowserRouter函数创建路由配置，使用<code>&lt;RouterProvider router={router}/&gt;</code>组件绑定返回的路由配置</p><p>createBrowserRouter相当于vue的createRouter，RouterProvider组件绑定后相当于vue的<code>app.use(router)</code>+<code>&lt;router-view/&gt;</code> 要创建hash模式的router需要使用createHashRouter</p><h1 id="redux" tabindex="-1"><a class="header-anchor" href="#redux"><span>redux</span></a></h1><h2 id="三个核心概念" tabindex="-1"><a class="header-anchor" href="#三个核心概念"><span>三个核心概念</span></a></h2><h3 id="action" tabindex="-1"><a class="header-anchor" href="#action"><span>action</span></a></h3><p>动作的对象，包含2个属性</p><ol><li>type：标识属性，值为字符串，唯一，必要属性</li><li>data：数据属性，值类型任意，可选属性</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{type:ADD_STUDENT&#39;data:{(name:&#39;tom&#39;age:18}}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="reducer" tabindex="-1"><a class="header-anchor" href="#reducer"><span>reducer</span></a></h3><p>用于初始化状态、加工状态。 加工时，根据l旧的state和action，产生新的state的纯函数。</p><h3 id="store" tabindex="-1"><a class="header-anchor" href="#store"><span>store</span></a></h3><p>将state、action、reducer联系在一起的对象</p><h2 id="步骤" tabindex="-1"><a class="header-anchor" href="#步骤"><span>步骤</span></a></h2><ol><li>定义一个reducer函数（根据当前想要做的修改返回一个新的状态）</li><li>使用createStore方法传入reducer函数生成一个store实例对象</li><li>使用store实例的subscribe方法订阅数据的变化（数据一旦变化，可以得到通知）</li><li>使用store实例的dispatch方法提交action对象触发数据变化（告诉reducer你想怎么改数据）</li><li>使用store实例的getState方法获取最新的状态数据更新到视图中</li></ol><h2 id="reduxjs-toolkit" tabindex="-1"><a class="header-anchor" href="#reduxjs-toolkit"><span>reduxjs/toolkit</span></a></h2><p>原本的redux比较难用，后来经过几次封装reduxjs/toolkit是一种比较常用的方案，使用方法也更贴近于vuex</p><p>在业务比较复杂的情况下推荐使用切片的方式，将不同业务分割为不同的切片</p><ol><li>创建切片</li></ol><ul><li>name：切片命名，必填</li><li>initialState：初始化State，其中的数据可以被reducers中的函数使用</li><li>reducers：定义修改状态的函数，相当于vuex中mutation</li><li>extraReducers：异步的函数，异步函数需要使用createAsyncThunk创建</li></ul><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let changeNumThunk = createAsyncThunk(&#39;numSlice/changeMes&#39;,async()=&gt;{</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let countSlice = createSlice({</span></span>
<span class="line"><span>	name:&#39;countSlice&#39;,</span></span>
<span class="line"><span>	initialState:{</span></span>
<span class="line"><span>		count:0</span></span>
<span class="line"><span>	},</span></span>
<span class="line"><span>	reducers:{</span></span>
<span class="line"><span>		addNum(state,action){</span></span>
<span class="line"><span>			state.num++</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}，</span></span>
<span class="line"><span>	extraReducers:(chunk)=&gt;{</span></span>
<span class="line"><span>		chunk.addCase(changeNumThunk.pending,()=&gt;{</span></span>
<span class="line"><span>			// pending状态做的处理</span></span>
<span class="line"><span>		})</span></span>
<span class="line"><span>		.addCase(changeNumThunk.fulfilled,(state,action)=&gt;{</span></span>
<span class="line"><span>			// fulfilled阶段做的处理</span></span>
<span class="line"><span>		})</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><ol start="2"><li>根据切片生成store</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let store = configureStore({</span></span>
<span class="line"><span>	reducer:{</span></span>
<span class="line"><span>		numReducer:numSlice.reducer,</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,59)]))}const p=s(t,[["render",l]]),c=JSON.parse('{"path":"/front/react/2/","title":"2 官方插件","lang":"zh-CN","frontmatter":{"title":"2 官方插件","createTime":"2025/06/01 19:30:08","permalink":"/front/react/2/"},"readingTime":{"minutes":5.17,"words":1551},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/React/2 官方插件.md","headers":[]}');export{p as comp,c as data};
